mapper.select:
select r.id, r.reporter_id, u.nickname as reporter_nickname, r.target_type, r.target_id, r.reason_type, r.reason, r.media_ids_json, r.status, r.handler_id, r.handle_result, r.handled_at, r.created_at from cook_reports r inner join cook_users u on u.id = r.reporter_id and u.deleted_at is null where r.deleted_at is null
and r.status = #{status}
and r.target_type = #{targetType}
order by r.created_at desc, r.id desc

mapper.insert:
insert into cook_media_upload_sessions (
    session_id, owner_id, object_key, original_name, content_type, size_bytes, fingerprint, status,
    media_id, error_message, expires_at
) values (
    #{sessionId}, #{ownerId}, #{objectKey}, #{originalName}, #{contentType}, #{sizeBytes}, #{fingerprint}, #{status},
    #{mediaId}, #{errorMessage}, #{expiresAt}
)
